UPDATE spells SET summary = 'Invisible magical eye hovers in place. You see through it (normal vision + {@sense darkvision} 30 ft). Move it 30 ft as action. No range limit, won''t cross planes. Solid barriers block it.''' WHERE slug = 'arcane-eye';
UPDATE spells SET summary = 'Target Charisma save or banished to harmless demiplane. Native creatures incapacitated, return when spell ends. Non-natives return after 1 min or stay permanently.''' WHERE slug = 'banishment';
UPDATE spells SET summary = '{@damage 8d8} necrotic damage (half on save). No effect on undead/constructs. Plants save with disadvantage, take max damage. Nonmagical plants wither.''' WHERE slug = 'blight';
UPDATE spells SET summary = 'Charmed creatures must move in direction you choose each turn as bonus action. Can take action first. Can make Wisdom save to end at turn end. Won''t move into obvious death.''' WHERE slug = 'compulsion';
UPDATE spells SET summary = 'Creatures in 10-ft sphere, {@condition blinded|blinded} at save or affected. Can''t take reactions. Roll {@dice d10} at turn start for random behavior. Save at end of turn to end effect.''' WHERE slug = 'confusion';
UPDATE spells SET summary = 'Summon elementals (1 CR 2, 2 CR 1, 4 CR 1/2, or 8 CR 1/4). Friendly, obey commands. Disappear at 0 HP or spell ends. DM has statistics.''' WHERE slug = 'conjure-minor-elementals';
UPDATE spells SET summary = 'Summon fey creatures (1 CR 2, 2 CR 1, 4 CR 1/2, or 8 CR 1/4). Friendly, obey commands. Disappear at 0 HP or spell ends. DM has statistics.''' WHERE slug = 'conjure-woodland-beings';
UPDATE spells SET summary = 'Control water in 100-ft cube. Flood (raise level 20 ft), Part Water (trench), Redirect Flow, or Whirlpool. Can change effect as action. Complex mechanics—DM adjudicates.''' WHERE slug = 'control-water';
UPDATE spells SET summary = 'Teleport self precisely to location within range (seen, visualized, or described). Can bring willing creature/objects (carrying capacity limit). Collision: {@damage 4d6} force damage, spell fails.''' WHERE slug = 'dimension-door';
UPDATE spells SET summary = 'Ask god one question about next 7 days. Get truthful answer (phrase, rhyme, or omen). No account for changing circumstances. 25% cumulative failure chance per casting after first in same rest.''' WHERE slug = 'divination';
UPDATE spells SET summary = 'Save or charmed. Mental commands 1 mile away. Total control for 1 turn. Retry if hurt.''' WHERE slug = 'dominate-beast';
UPDATE spells SET summary = 'Convert raw materials into items of same material. Large or smaller (10-ft cube). Medium max if stone/metal. Can''t make magic items or complex items requiring special tools.''' WHERE slug = 'fabricate';
UPDATE spells SET summary = 'Summon celestial/fey/fiend mount (griffon, pegasus, peryton, dire wolf, rhinoceros, saber-tooth). Telepathy 1 mile. Spell targets you also target mount. Dismissible.''' WHERE slug = 'find-greater-steed';
UPDATE spells SET summary = 'Warm or chill shield. Grant cold or fire resistance respectively. Attacker within 5 ft: {@damage 2d8} fire/cold damage. Bright light 10 ft, dim 10 ft more.''' WHERE slug = 'fire-shield';
UPDATE spells SET summary = 'Transform insects to giant size: 10 centipedes, 3 spiders, 5 wasps, or 1 scorpion. Friendly, obey commands, act on your turn.''' WHERE slug = 'giant-insect';
UPDATE spells SET summary = 'Spectral guardian appears. Hostile creatures within 10 ft save or take 20 radiant damage (half on save). Vanishes after 60 damage dealt.''' WHERE slug = 'guardian-of-faith';
UPDATE spells SET summary = 'Transform into Primal Beast (+10 ft speed, {@sense darkvision} 120 ft, Str advantage, +{@damage 1d6} force on melee) or Great Tree (10 temp HP, Con saves advantage, difficult terrain aura).''' WHERE slug = 'guardian-of-nature';
UPDATE spells SET summary = '150-ft cube appears as different terrain. Tactile check (Investigation DC save) to disbelieve. Structures/creatures/equipment unchanged. Perceives as vague overlay once disbelieved.''' WHERE slug = 'hallucinatory-terrain';
UPDATE spells SET summary = 'Sense direction to creature within 1,000 ft. Describe or name a specific creature you know or nearest of a type you''ve seen. Won''t work if under {@spell polymorph} or across running water (10 ft+).''' WHERE slug = 'locate-creature';
UPDATE spells SET summary = 'Transform creature into any beast of equal/lower CR. Beast stats replace original (mental ability scores too). Retain personality/alignment. Reverts at 0 HP or duration ends.''' WHERE slug = 'polymorph';
UPDATE spells SET summary = 'Teleport self. Everyone within 10 ft of starting point: {@damage 3d10} thunder damage (half on save). Can bring 1 willing creature or objects.''' WHERE slug = 'thunder-step';
UPDATE spells SET summary = 'Wave up to 30×10×10 ft. Creatures save or take {@damage 4d8} bludgeoning + knocked {@condition prone}. Water extinguishes flames, spreads then vanishes.''' WHERE slug = 'tidal-wave';
UPDATE spells SET summary = 'Animate tiny object. Command it mentally (120 ft range). Follows orders like fetch, guard, stack. Returns to original form at 0 HP.''' WHERE slug = 'tiny-servant';
UPDATE spells SET summary = '30 ft long or 20 ft diameter ringed wall. Difficult terrain. Ranged attacks disadvantage. Fire damage halved. Cold spells freeze 5-ft sections (AC 5, 15 HP each).''' WHERE slug = 'wall-of-water';
UPDATE spells SET summary = 'Wall 50 ft long, 15 ft high. {@damage 3d8} bludgeoning (half on save). Blocks fog/gases, small creatures, projectiles. {@spell gaseous form} can''t pass.''' WHERE slug = 'wind-wall';
